// src/components/common/RoleBasedNav.js
import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useRole } from '../../context/RoleContext';
import PermissionGate from './PermissionGate';
import './RoleBasedNav.css';

const RoleBasedNav = () => {
    const { user, logout } = useAuth();
    const { userRole, isRole } = useRole();
    const navigate = useNavigate();

    const handleLogout = () => {
        logout();
        navigate('/');
    };

    const getRoleIcon = () => {
        switch(userRole) {
            case 'master_admin':
                return '👑';
            case 'doctor':
                return '👨‍⚕️';
            case 'nurse':
                return '👩‍⚕️';
            case 'diagnostic_staff':
            case 'lab_technician':
            case 'radiologist':
                return '🔬';
            case 'therapeutic_staff':
            case 'physiotherapist':
            case 'nutritionist':
                return '💪';
            case 'pharmacist':
                return '💊';
            case 'receptionist':
                return '📋';
            case 'billing_officer':
                return '💰';
            case 'ict_admin':
                return '💻';
            case 'hr_admin':
                return '👥';
            case 'department_head':
                return '👔';
            default:
                return '👤';
        }
    };

    const getRoleDisplayName = () => {
        switch(userRole) {
            case 'master_admin':
                return 'Master Admin';
            case 'doctor':
                return 'Doctor';
            case 'nurse':
                return 'Nurse';
            case 'diagnostic_staff':
                return 'Diagnostic Staff';
            case 'lab_technician':
                return 'Lab Technician';
            case 'radiologist':
                return 'Radiologist';
            case 'therapeutic_staff':
                return 'Therapeutic Staff';
            case 'physiotherapist':
                return 'Physiotherapist';
            case 'nutritionist':
                return 'Nutritionist';
            case 'pharmacist':
                return 'Pharmacist';
            case 'receptionist':
                return 'Receptionist';
            case 'billing_officer':
                return 'Billing Officer';
            case 'ict_admin':
                return 'ICT Admin';
            case 'hr_admin':
                return 'HR Admin';
            case 'department_head':
                return 'Department Head';
            default:
                return userRole?.replace('_', ' ').toUpperCase() || 'Patient';
        }
    };

    return (
        <nav className="role-nav">
            <div className="nav-container">
                <div className="nav-brand">
                    <Link to="/dashboard">
                        <h2>🏥 E-Health</h2>
                    </Link>
                </div>
                
                <div className="nav-menu">
                    <Link to="/dashboard" className="nav-link">Dashboard</Link>
                    
                    {/* Master Admin Links */}
                    {isRole('master_admin') && (
                        <>
                            <Link to="/admin" className="nav-link">👑 Admin Dashboard</Link>
                            <Link to="/admin/roles" className="nav-link">⚙️ Manage Roles</Link>
                            <Link to="/admin/verifications" className="nav-link">✅ Verifications</Link>
                        </>
                    )}
                    
                    {/* Patient/Clinical Permissions */}
                    <PermissionGate permissions={['view_patient_records', 'view_patient_list']}>
                        <Link to="/patients" className="nav-link">Patients</Link>
                    </PermissionGate>
                    
                    {/* Appointment Permissions */}
                    <PermissionGate permissions={['view_all_appointments', 'create_appointments', 'schedule_appointments']}>
                        <Link to="/appointments" className="nav-link">Appointments</Link>
                    </PermissionGate>
                    
                    {/* Prescription Permissions */}
                    <PermissionGate permissions={['view_all_prescriptions', 'create_prescriptions']}>
                        <Link to="/prescriptions" className="nav-link">Prescriptions</Link>
                    </PermissionGate>
                    
                    {/* Lab/Diagnostic Permissions */}
                    <PermissionGate permissions={['view_lab_requests', 'update_lab_results']}>
                        <Link to="/lab-requests" className="nav-link">Lab Requests</Link>
                    </PermissionGate>
                    
                    {/* Therapy Permissions */}
                    <PermissionGate permissions={['view_therapy_requests', 'create_therapy_plans']}>
                        <Link to="/therapy" className="nav-link">Therapy</Link>
                    </PermissionGate>
                    
                    {/* Billing/Payment Permissions */}
                    <PermissionGate permissions={['view_invoices', 'create_invoices']}>
                        <Link to="/billing" className="nav-link">Billing</Link>
                    </PermissionGate>
                    
                    {/* Staff Management (Admin/HR/ICT) */}
                    <PermissionGate permissions={['manage_staff', 'manage_users']}>
                        <Link to="/staff" className="nav-link">Staff Management</Link>
                    </PermissionGate>
                    
                    {/* Department Reports (Department Heads) */}
                    <PermissionGate permissions={['view_department_reports']}>
                        <Link to="/department-reports" className="nav-link">Reports</Link>
                    </PermissionGate>
                </div>
                
                <div className="nav-user">
                    <div className="user-info">
                        <span className="user-role-badge" title={getRoleDisplayName()}>
                            {getRoleIcon()}
                        </span>
                        <span className="user-name">{user?.username}</span>
                        {user?.verification_status === 'pending' && (
                            <span className="verification-pending" title="Pending Verification">⏳</span>
                        )}
                    </div>
                    <button onClick={handleLogout} className="logout-btn">
                        Logout
                    </button>
                </div>
            </div>
        </nav>
    );
};

export default RoleBasedNav;
